import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const TABS = ["overview", "students", "attendance", "subject"];

function MentorDashboard() {
  const navigate = useNavigate();
  const [mentor, setMentor] = useState(null);
  const [activeTab, setActiveTab] = useState("overview");
  const [students, setStudents] = useState([]);
  const [attendance, setAttendance] = useState([]);
  const [selectedSubject, setSelectedSubject] = useState("All");
  const [selectedDate, setSelectedDate] = useState("All");
  const [searchId, setSearchId] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const stored = localStorage.getItem("mentor");
    if (!stored) { navigate("/mentor"); return; }
    setMentor(JSON.parse(stored));
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [sRes, aRes] = await Promise.all([
        fetch("http://localhost:5000/students"),
        fetch("http://localhost:5000/attendance"),
      ]);
      const sData = await sRes.json();
      const aData = await aRes.json();
      setStudents(sData);
      setAttendance(aData);
    } catch (err) {
      console.error("Fetch error:", err);
    }
    setLoading(false);
  };

  const handleLogout = () => {
    localStorage.removeItem("mentor");
    navigate("/");
  };

  // Derived data
  const allSubjects = ["All", ...new Set(attendance.map((r) => r.subject).filter(Boolean))];
  const allDates = ["All", ...new Set(attendance.map((r) => r.date).filter(Boolean))];

  const filteredAttendance = attendance.filter((r) => {
    const subMatch = selectedSubject === "All" || r.subject === selectedSubject;
    const dateMatch = selectedDate === "All" || r.date === selectedDate;
    const idMatch = searchId === "" || r.studentId?.toLowerCase().includes(searchId.toLowerCase()) ||
      r.studentName?.toLowerCase().includes(searchId.toLowerCase());
    return subMatch && dateMatch && idMatch;
  });

  // Per-student attendance summary
  const studentSummary = students.map((s) => {
    const records = attendance.filter((r) => r.studentId === s.id);
    const subjects = [...new Set(records.map((r) => r.subject).filter(Boolean))];
    return { ...s, totalPresent: records.length, subjects };
  });

  // Per-subject summary
  const subjectSummary = allSubjects.filter(s => s !== "All").map((sub) => {
    const records = attendance.filter((r) => r.subject === sub);
    const uniqueStudents = new Set(records.map((r) => r.studentId)).size;
    return { subject: sub, totalMarked: records.length, uniqueStudents };
  });

  if (!mentor) return null;

  return (
    <div className="dashboard">
      {/* Sidebar */}
      <div className="sidebar">
        <h2>👨‍🏫 Mentor</h2>
        <p style={{ fontSize: "13px", color: "#aaa", marginBottom: "20px" }}>{mentor.name}</p>
        <ul>
          {[
            { key: "overview", label: "📊 Overview" },
            { key: "students", label: "👩‍🎓 Enrolled Students" },
            { key: "attendance", label: "✅ Attendance Records" },
            { key: "subject", label: "📚 Subject Summary" },
          ].map((item) => (
            <li key={item.key}
              onClick={() => setActiveTab(item.key)}
              style={{
                padding: "12px", marginBottom: "8px", cursor: "pointer",
                borderRadius: "6px", fontSize: "14px",
                background: activeTab === item.key ? "#2e3f54" : "transparent",
                borderLeft: activeTab === item.key ? "3px solid #007bff" : "3px solid transparent",
              }}>
              {item.label}
            </li>
          ))}
        </ul>
        <button onClick={handleLogout} style={{
          marginTop: "auto", width: "100%", padding: "10px",
          background: "#dc3545", color: "white", border: "none",
          borderRadius: "6px", cursor: "pointer", position: "absolute", bottom: "20px", left: "20px", width: "190px",
        }}>🚪 Logout</button>
      </div>

      {/* Main */}
      <div className="main">

        {/* Refresh button */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "20px" }}>
          <h2 style={{ margin: 0 }}>
            {activeTab === "overview" && "📊 Dashboard Overview"}
            {activeTab === "students" && "👩‍🎓 Enrolled Students"}
            {activeTab === "attendance" && "✅ Attendance Records"}
            {activeTab === "subject" && "📚 Subject-wise Summary"}
          </h2>
          <button onClick={fetchData} style={{
            padding: "8px 16px", background: "#007bff", color: "white",
            border: "none", borderRadius: "6px", cursor: "pointer", fontSize: "13px",
          }}>🔄 Refresh</button>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "40px", color: "#888" }}>⏳ Loading data...</div>
        ) : (
          <>
            {/* OVERVIEW TAB */}
            {activeTab === "overview" && (
              <div>
                {/* Stat Cards */}
                <div style={{ display: "flex", gap: "20px", flexWrap: "wrap", marginBottom: "25px" }}>
                  {[
                    { label: "Total Students", value: students.length, icon: "👩‍🎓", color: "#007bff" },
                    { label: "Total Attendance", value: attendance.length, icon: "✅", color: "#28a745" },
                    { label: "Subjects Active", value: subjectSummary.length, icon: "📚", color: "#fd7e14" },
                    { label: "Today's Records", value: attendance.filter(r => r.date === new Date().toLocaleDateString("en-IN")).length, icon: "📅", color: "#6f42c1" },
                  ].map((card, i) => (
                    <div key={i} style={{
                      flex: "1", minWidth: "140px", background: "white", padding: "20px",
                      borderRadius: "10px", boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
                      borderTop: `4px solid ${card.color}`, textAlign: "center",
                    }}>
                      <div style={{ fontSize: "32px" }}>{card.icon}</div>
                      <div style={{ fontSize: "28px", fontWeight: "bold", color: card.color }}>{card.value}</div>
                      <div style={{ fontSize: "13px", color: "#888", marginTop: "4px" }}>{card.label}</div>
                    </div>
                  ))}
                </div>

                {/* Recent Attendance */}
                <div className="content">
                  <h4>🕐 Recent Attendance (Last 10)</h4>
                  {attendance.length === 0 ? (
                    <p style={{ color: "#888", marginTop: "10px" }}>No attendance records yet.</p>
                  ) : (
                    <table className="timetable" style={{ marginTop: "10px" }}>
                      <thead>
                        <tr><th>Student</th><th>ID</th><th>Subject</th><th>Date</th><th>Time</th><th>Status</th></tr>
                      </thead>
                      <tbody>
                        {[...attendance].reverse().slice(0, 10).map((r, i) => (
                          <tr key={i}>
                            <td>{r.studentName}</td>
                            <td>{r.studentId}</td>
                            <td><strong>{r.subject}</strong></td>
                            <td>{r.date}</td>
                            <td>{r.time}</td>
                            <td style={{ color: "green", fontWeight: "bold" }}>✅ {r.status}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
                </div>
              </div>
            )}

            {/* STUDENTS TAB */}
            {activeTab === "students" && (
              <div className="content">
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "15px" }}>
                  <h4>Total Enrolled: <span style={{ color: "#007bff" }}>{students.length}</span></h4>
                  <input
                    placeholder="🔍 Search by name or ID..."
                    value={searchId}
                    onChange={(e) => setSearchId(e.target.value)}
                    style={{ padding: "8px 12px", border: "1px solid #ddd", borderRadius: "6px", width: "220px" }}
                  />
                </div>
                {students.length === 0 ? (
                  <p style={{ color: "#888" }}>No students registered yet.</p>
                ) : (
                  <table className="timetable">
                    <thead>
                      <tr><th>#</th><th>Name</th><th>Student ID</th><th>Branch</th><th>Section</th><th>Attendance Count</th><th>Subjects Attended</th></tr>
                    </thead>
                    <tbody>
                      {studentSummary
                        .filter(s => searchId === "" ||
                          s.name?.toLowerCase().includes(searchId.toLowerCase()) ||
                          s.id?.toLowerCase().includes(searchId.toLowerCase()))
                        .map((s, i) => (
                          <tr key={i}>
                            <td>{i + 1}</td>
                            <td><strong>{s.name}</strong></td>
                            <td>{s.id}</td>
                            <td>{s.branch}</td>
                            <td>{s.section}</td>
                            <td>
                              <span style={{
                                background: s.totalPresent > 0 ? "#d4edda" : "#f8d7da",
                                color: s.totalPresent > 0 ? "#155724" : "#721c24",
                                padding: "3px 10px", borderRadius: "12px", fontWeight: "bold",
                              }}>{s.totalPresent}</span>
                            </td>
                            <td style={{ fontSize: "12px" }}>
                              {s.subjects.length === 0 ? <span style={{ color: "#888" }}>None</span> :
                                s.subjects.map((sub, j) => (
                                  <span key={j} style={{
                                    background: "#e3f2fd", color: "#1565c0", padding: "2px 8px",
                                    borderRadius: "10px", margin: "2px", display: "inline-block", fontSize: "11px",
                                  }}>{sub}</span>
                                ))}
                            </td>
                          </tr>
                        ))}
                    </tbody>
                  </table>
                )}
              </div>
            )}

            {/* ATTENDANCE TAB */}
            {activeTab === "attendance" && (
              <div className="content">
                {/* Filters */}
                <div style={{ display: "flex", gap: "12px", flexWrap: "wrap", marginBottom: "15px" }}>
                  <select value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)}
                    style={{ padding: "8px 12px", border: "1px solid #ddd", borderRadius: "6px" }}>
                    {allSubjects.map((s, i) => <option key={i} value={s}>{s === "All" ? "📚 All Subjects" : s}</option>)}
                  </select>
                  <select value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)}
                    style={{ padding: "8px 12px", border: "1px solid #ddd", borderRadius: "6px" }}>
                    {allDates.map((d, i) => <option key={i} value={d}>{d === "All" ? "📅 All Dates" : d}</option>)}
                  </select>
                  <input placeholder="🔍 Search student..."
                    value={searchId} onChange={(e) => setSearchId(e.target.value)}
                    style={{ padding: "8px 12px", border: "1px solid #ddd", borderRadius: "6px", flex: 1 }} />
                </div>

                <p style={{ color: "#888", fontSize: "13px", marginBottom: "10px" }}>
                  Showing <strong>{filteredAttendance.length}</strong> records
                </p>

                {filteredAttendance.length === 0 ? (
                  <p style={{ color: "#888" }}>No attendance records found.</p>
                ) : (
                  <table className="timetable">
                    <thead>
                      <tr><th>#</th><th>Student Name</th><th>Student ID</th><th>Subject</th><th>Date</th><th>Time</th><th>Method</th><th>Status</th></tr>
                    </thead>
                    <tbody>
                      {filteredAttendance.map((r, i) => (
                        <tr key={i}>
                          <td>{i + 1}</td>
                          <td><strong>{r.studentName}</strong></td>
                          <td>{r.studentId}</td>
                          <td>{r.subject}</td>
                          <td>{r.date}</td>
                          <td>{r.time}</td>
                          <td>{r.method}</td>
                          <td style={{ color: "green", fontWeight: "bold" }}>✅ Present</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            )}

            {/* SUBJECT TAB */}
            {activeTab === "subject" && (
              <div className="content">
                <h4 style={{ marginBottom: "15px" }}>Subject-wise Attendance Summary</h4>
                {subjectSummary.length === 0 ? (
                  <p style={{ color: "#888" }}>No attendance data yet.</p>
                ) : (
                  <div style={{ display: "flex", flexWrap: "wrap", gap: "15px" }}>
                    {subjectSummary.map((s, i) => (
                      <div key={i} style={{
                        background: "white", border: "1px solid #e0e0e0", borderRadius: "10px",
                        padding: "20px", minWidth: "200px", flex: "1",
                        boxShadow: "0 2px 8px rgba(0,0,0,0.08)", borderTop: "4px solid #007bff",
                      }}>
                        <h4 style={{ color: "#007bff", marginBottom: "12px" }}>📖 {s.subject}</h4>
                        <p style={{ fontSize: "13px", color: "#555", marginBottom: "6px" }}>
                          Total Records: <strong>{s.totalMarked}</strong>
                        </p>
                        <p style={{ fontSize: "13px", color: "#555" }}>
                          Unique Students: <strong>{s.uniqueStudents}</strong>
                        </p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default MentorDashboard;
